const store = $getWorkflowStaticData('global');

const payload = {
  output_file: store.output_file,
  sheet: "Berichte",
  row: [
    $('parse pdfminer').first().json.fileName ?? "",
    $input.first().json.Firma ?? "",
    $input.first().json['Art des Jobs'] ?? "",
    $input.first().json['Mitgebrachte Kenntnisse und Lehrveranstaltungen'] ?? "",
    $input.first().json['Fehlende Kenntnisse und Lehrveranstaltungen'] ?? ""
  ]
};

const payload_b64 = Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');

return [{
  json: {
    payload_b64
  }
}];

function normSpaces(s) {
  return String(s ?? '').replace(/\s+/g, ' ').trim();
}

function stripLegalForms(s) {
  // konservativ: entfernt häufige Rechtsformen am Ende oder als eigenes Token
  // (kannst du erweitern)
  return s
    .replace(/\b(gmbh|mbh|ag|se|kg|ohg|gbr|eg|ug|kgaa|inc|ltd|llc|sarl|sa)\b\.?/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeCompany(raw) {
  let s = normSpaces(raw);
  if (!s) return '';

  // vereinheitlichen
  s = s.toLowerCase();

  // & -> und
  s = s.replace(/&/g, ' und ');

  // Klammerzusätze raus (z.B. "(Berlin)")
  s = s.replace(/\([^)]*\)/g, ' ');

  // Satzzeichen raus, Bindestriche als Space
  s = s.replace(/[-–—_/\\.,:;|]+/g, ' ');

  // Rechtsformen raus
  s = stripLegalForms(s);

  // erneut spaces
  s = normSpaces(s);

  return s;
}

// Optional: Alias Map (für Abkürzungen / bekannte Varianten)
const ALIAS = {
  // Beispiele (falls du später willst, hier erweitern):
  // 'vw': 'volkswagen',
  // 'db': 'deutsche bahn',
  // 'telekom': 'deutsche telekom',
};

function canonicalCompany(raw) {
  const n = normalizeCompany(raw);
  if (!n) return '';
  return ALIAS[n] || n;
}

function splitSkills(cell) {
  const raw = normSpaces(cell);
  if (!raw) return [];
  return raw
    .split(/[;\n,]+/g)
    .map(s => normSpaces(s))
    .filter(Boolean);
}

function normalizeSkill(raw) {
  let s = normSpaces(raw);
  if (!s) return '';
  s = s.toLowerCase();

  // typische Vereinheitlichungen
  s = s.replace(/\bms\b/g, 'microsoft');
  s = s.replace(/[-–—_/\\]+/g, ' ');
  s = s.replace(/\s+/g, ' ').trim();

  return s;
}

function topNFromMap(map, n) {
  return [...map.entries()]
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0], 'de'))
    .slice(0, n)
    .map(([name, count]) => ({ name, count }));
}

const items = $input.all();
if (items.length === 0) {
  throw new Error('Keine Input-Items bekommen.');
}

// XLSX Path aus erstem Item (wird in jedem Item mitgeführt)
const xlsxPath = items[0].json.__xlsxPath;

// Counts
const companyCounts = new Map();
const skillCounts = new Map();

// Für Transparenz: Roh->Canonical Mapping mitzählen
const companyVariants = new Map(); // canonical -> Set(raw variants)

for (const it of items) {
  const firmaRaw = it.json['Firma'];
  const canonical = canonicalCompany(firmaRaw);

  if (canonical) {
    companyCounts.set(canonical, (companyCounts.get(canonical) || 0) + 1);

    const set = companyVariants.get(canonical) || new Set();
    set.add(normSpaces(firmaRaw));
    companyVariants.set(canonical, set);
  }

  // Skills: pro Bericht deduplizieren (damit doppelte Nennungen in einer Zelle nicht aufblasen)
  const skillsRaw = it.json['Mitgebrachte Kenntnisse und Lehrveranstaltungen'];
  const skills = splitSkills(skillsRaw).map(normalizeSkill).filter(Boolean);
  const uniq = new Set(skills);

  for (const s of uniq) {
    skillCounts.set(s, (skillCounts.get(s) || 0) + 1);
  }
}

const topCompanies = topNFromMap(companyCounts, 3);
const topSkills = topNFromMap(skillCounts, 3);

// companyVariants in JSON-friendly Form
const companyVariantsObj = {};
for (const [canon, set] of companyVariants.entries()) {
  companyVariantsObj[canon] = [...set].sort((a, b) => a.localeCompare(b, 'de'));
}

return [{
  json: {
    xlsxPath,
    topCompanies,
    topSkills,
    companyVariants: companyVariantsObj,
    totals: {
      rows: items.length,
      uniqueCompanies: companyCounts.size,
      uniqueSkills: skillCounts.size,
    }
  }
}];
